import { Body, Get, JsonController, Param, Patch, Post, QueryParams } from 'routing-controllers';
import { Service } from 'typedi';

import { ServiceRegistryGuard } from '@Middlewares/guard/ServiceRegistryGuard';

import { PriceSettingService } from '@Services/PriceSettingService';

import { CreatePriceSettingDto, PriceSettingQueryParams, UpdatePriceSettingDto } from '@Rests/types/PriceSettingDto';

@Service()
@JsonController('/price-settings')
@ServiceRegistryGuard()
export class PriceSettingController {
  constructor(private readonly service: PriceSettingService) { }

  @Post('')
  create(@Body() dto: CreatePriceSettingDto) {
    return this.service.create(dto);
  }

  @Get('')
  findAll(@QueryParams() query: PriceSettingQueryParams) {
    return this.service.findAll(query);
  }

  @Get('/hotel/:hotelId/rate-plan')
  getHotelRatePlan(@Param('hotelId') hotelId: number) {
    return this.service.getByHotelRatePlan(hotelId);
  }

  @Get('/hotel/:hotelId/rate-plan/:id')
  getHotelRatePlanDetail(@Param('id') id: number, @Param('hotelId') hotelId: number) {
    return this.service.getHotelRatePlanDetail(id, hotelId);
  }

  @Get('/:id')
  getById(@Param('id') id: number) {
    return this.service.getById(id);
  }

  @Patch('/:id')
  partialUpdate(@Param('id') id: number, @Body() dto: UpdatePriceSettingDto) {
    return this.service.partialUpdate(id, dto);
  }

  @Post('/:id/absolute-overlaps')
  checkAbsoluteOverlaps(@Param('id') id: number) {
    return this.service.checkAbsoluteOverlaps(id);
  }
}

