  /** Đồng bộ dữ liệu price setting vào bảng rate_calendar theo các ngày áp dụng */
  private async syncRateCalendar(priceSetting: PriceSetting, previousPeriods: RangeDate[] = []) {
    const hotelId = priceSetting.hotel?.id;
    const roomId = priceSetting.room?.id;
    const priceSettingId = priceSetting.id;

    if (!hotelId || !roomId) return;

    const today = dayjs().startOf('day');
    const filterStayDatesFromToday = (dates: string[]) =>
      dates.filter(dateStr => !dayjs(dateStr).startOf('day').isBefore(today));

    const dayFilter = await this.resolveSeasonDayFilter(priceSetting, hotelId);

    const previousStayDates = filterStayDatesFromToday(
      this.buildStayDates(previousPeriods, { seasonDay: dayFilter, dayType: priceSetting.dayType }),
    );

    if (previousStayDates.length > 0) {
      await this.rateCalendarRepo.deleteByHotelRoomAndDates(hotelId, roomId, previousStayDates, {
        priceSettingId,
        mealPlan: priceSetting.mealPlan,
      });
    }

    if (!priceSetting.isActive) {
      return;
    }

    const nextStayDates = filterStayDatesFromToday(
      this.buildStayDates(priceSetting.periods, { seasonDay: dayFilter, dayType: priceSetting.dayType }),
    );

    if (!nextStayDates.length) {
      return;
    }

    const stayDateObjects = nextStayDates.map(dateStr => dayjs(dateStr).toDate());
    const existingRateCalendars = await this.rateCalendarRepo.find({
      where: {
        hotelId,
        roomId,
        stayDate: In(stayDateObjects),
        mealPlan: priceSetting.mealPlan,
        condition: priceSetting.condition,
      },
    });

    const buildUniqueKey = (
      hotel: number,
      room: number,
      stayDate: string,
      mealPlan?: MealPlan | null,
      condition?: CancellationType | null,
    ) => `${hotel}|${room}|${stayDate}|${mealPlan ?? 'null'}|${condition ?? 'null'}`;

    const existedMap = new Map<string, RateCalendar>();
    existingRateCalendars.forEach(item => {
      const key = buildUniqueKey(
        hotelId,
        roomId,
        dayjs(item.stayDate).format('YYYY-MM-DD'),
        item.mealPlan,
        item.condition,
      );
      existedMap.set(key, item);
    });

